     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→    <meta charset="UTF-8">
     5→    <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→    <title>Interactive Canvas - Semantic Zoom Demo</title>
     7→    <script src="https://cdn.tailwindcss.com"></script>
     8→    <style>
     9→        /* Custom scrollbar */
    10→        ::-webkit-scrollbar { width: 8px; height: 8px; }
    11→        ::-webkit-scrollbar-track { background: #f1f1f1; }
    12→        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 4px; }
    13→        ::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
    14→
    15→        /* Task gradients */
    16→        .task-block.blue { background: linear-gradient(135deg, #3b82f6, #2563eb); }
    17→        .task-block.orange { background: linear-gradient(135deg, #f59e0b, #d97706); }
    18→        .task-block.gray { background: linear-gradient(135deg, #9ca3af, #6b7280); }
    19→        .task-block.conflict { box-shadow: 0 0 0 2px #ef4444, 0 0 12px rgba(239, 68, 68, 0.4); }
    20→    </style>
    21→</head>
    22→<body class="font-sans bg-gray-100 text-gray-800 h-screen overflow-hidden">
    23→    <!-- Header -->
    24→    <div class="flex items-center justify-between px-4 py-2 bg-white border-b border-gray-200 h-12 shadow-sm">
    25→        <div class="flex items-center gap-3">
    26→            <span class="text-lg text-gray-500 cursor-pointer hover:text-gray-700">☰</span>
    27→            <span class="text-sm font-semibold text-gray-900">Interactive Canvas - Semantic Zoom</span>
    28→        </div>
    29→        <div class="flex items-center gap-4">
    30→            <div class="flex items-center gap-2 text-xs text-gray-500">
    31→                <span>Zoom:</span>
    32→                <span id="zoomLevel" class="font-mono font-semibold text-gray-700">1.00x</span>
    33→            </div>
    34→            <div class="flex items-center gap-2 text-xs text-gray-500">
    35→                <span>LOD:</span>
    36→                <span id="lodLevel" class="font-mono font-semibold px-2 py-0.5 rounded bg-blue-100 text-blue-700">MESO</span>
    37→            </div>
    38→            <button id="resetBtn" class="px-3 py-1 bg-gray-100 hover:bg-gray-200 border border-gray-300 rounded text-xs cursor-pointer transition-colors">
    39→                Reset View
    40→            </button>
    41→        </div>
    42→    </div>
    43→
    44→    <!-- Main Container -->
    45→    <div class="flex h-[calc(100vh-48px)]">
    46→        <!-- Sidebar - Train IDs -->
    47→        <div id="sidebar" class="w-16 bg-white border-r border-gray-200 flex flex-col overflow-hidden">
    48→            <div class="p-2 text-[10px] font-semibold text-gray-500 border-b border-gray-200 text-center">ID</div>
    49→            <div id="trainList" class="flex-1 overflow-hidden"></div>
    50→        </div>
    51→
    52→        <!-- Canvas Container -->
    53→        <div class="flex-1 relative overflow-hidden bg-gray-50">
    54→            <!-- Timeline Header -->
    55→            <div id="timelineHeader" class="absolute top-0 left-0 right-0 h-8 bg-white border-b border-gray-200 z-10 flex items-center overflow-hidden"></div>
    56→
    57→            <!-- Main Canvas -->
    58→            <canvas id="mainCanvas" class="absolute top-8 left-0 cursor-grab active:cursor-grabbing"></canvas>
    59→
    60→            <!-- Micro Layer HTML Overlay (visible at high zoom) -->
    61→            <div id="microOverlay" class="absolute top-8 left-0 pointer-events-none opacity-0 transition-opacity duration-300"></div>
    62→
    63→            <!-- Zoom Controls -->
    64→            <div class="absolute bottom-4 right-4 flex flex-col gap-1 bg-white rounded-lg shadow-lg border border-gray-200 overflow-hidden z-20">
    65→                <button id="zoomIn" class="w-10 h-10 flex items-center justify-center text-lg text-gray-600 hover:bg-gray-100 transition-colors">+</button>
    66→                <div class="h-px bg-gray-200"></div>
    67→                <button id="zoomOut" class="w-10 h-10 flex items-center justify-center text-lg text-gray-600 hover:bg-gray-100 transition-colors">−</button>
    68→            </div>
    69→
    70→            <!-- LOD Legend -->
    71→            <div class="absolute bottom-4 left-4 bg-white rounded-lg shadow-lg border border-gray-200 p-3 z-20 text-xs">
    72→                <div class="font-semibold text-gray-700 mb-2">Zoom Levels (LOD)</div>
    73→                <div class="flex items-center gap-2 mb-1">
    74→                    <div class="w-3 h-3 rounded-sm bg-yellow-400"></div>
    75→                    <span class="text-gray-600">Macro (&lt;0.5x) - Heatmap</span>
    76→                </div>
    77→                <div class="flex items-center gap-2 mb-1">
    78→                    <div class="w-3 h-3 rounded-sm bg-blue-500"></div>
    79→                    <span class="text-gray-600">Meso (0.5-2x) - DNA Strips</span>
    80→                </div>
    81→                <div class="flex items-center gap-2">
    82→                    <div class="w-3 h-3 rounded-sm bg-green-500"></div>
    83→                    <span class="text-gray-600">Micro (&gt;2x) - Task Cards</span>
    84→                </div>
    85→            </div>
    86→
    87→            <!-- Instructions -->
    88→            <div class="absolute top-12 left-1/2 -translate-x-1/2 bg-black/70 text-white text-xs px-4 py-2 rounded-full z-20 pointer-events-none transition-opacity duration-500" id="instructions">
    89→                Scroll to zoom • Drag to pan • Double-click to zoom in
    90→            </div>
    91→        </div>
    92→    </div>
    93→
    94→    <script>
    95→        // ========================================
    96→        // CONFIGURATION
    97→        // ========================================
    98→        const CONFIG = {
    99→            TRAINS: 50,
   100→            YEARS: 10,
   101→            PX_PER_DAY: 10,
   102→            PX_PER_TRAIN: 24,
   103→            START_DATE: new Date(2024, 0, 1),
   104→            MIN_ZOOM: 0.1,
   105→            MAX_ZOOM: 5,
   106→            ZOOM_SENSITIVITY: 0.002,
   107→            LOD_THRESHOLDS: {
   108→                MACRO: 0.5,    // Below this = Macro
   109→                MICRO: 2.0    // Above this = Micro
   110→            }
   111→        };
   112→
   113→        // ========================================
   114→        // STATE
   115→        // ========================================
   116→        const state = {
   117→            zoom: 1.0,
   118→            panX: 0,
   119→            panY: 0,
   120→            isDragging: false,
   121→            dragStartX: 0,
   122→            dragStartY: 0,
   123→            lastPanX: 0,
   124→            lastPanY: 0,
   125→            currentLOD: 'MESO',
   126→            tasks: [],
   127→            trains: []
   128→        };
   129→
   130→        // ========================================
   131→        // DOM ELEMENTS
   132→        // ========================================
   133→        const canvas = document.getElementById('mainCanvas');
   134→        const ctx = canvas.getContext('2d');
   135→        const sidebar = document.getElementById('trainList');
   136→        const timelineHeader = document.getElementById('timelineHeader');
   137→        const microOverlay = document.getElementById('microOverlay');
   138→        const zoomLevelEl = document.getElementById('zoomLevel');
   139→        const lodLevelEl = document.getElementById('lodLevel');
   140→        const instructions = document.getElementById('instructions');
   141→
   142→        // ========================================
   143→        // DATA GENERATION
   144→        // ========================================
   145→        function generateData() {
   146→            // Generate trains
   147→            state.trains = Array.from({ length: CONFIG.TRAINS }, (_, i) => ({
   148→                id: `T${String(i + 1).padStart(3, '0')}`,
   149→                name: `Train ${i + 1}`,
   150→                type: i < 30 ? 'ALSTOM' : 'KINKI'
   151→            }));
   152→
   153→            // Generate tasks
   154→            state.tasks = [];
   155→            const taskTypes = ['maintenance', 'overhaul', 'inspection'];
   156→            const colors = ['blue', 'orange', 'gray'];
   157→
   158→            state.trains.forEach((train, trainIndex) => {
   159→                // Generate ~10 tasks per year per train
   160→                for (let year = 0; year < CONFIG.YEARS; year++) {
   161→                    const tasksPerYear = 8 + Math.floor(Math.random() * 5);
   162→                    for (let t = 0; t < tasksPerYear; t++) {
   163→                        const dayOffset = year * 365 + Math.floor(Math.random() * 360);
   164→                        const duration = 2 + Math.floor(Math.random() * 10);
   165→                        const typeIndex = Math.floor(Math.random() * taskTypes.length);
   166→
   167→                        state.tasks.push({
   168→                            id: `${train.id}-${year}-${t}`,
   169→                            trainId: train.id,
   170→                            trainIndex,
   171→                            startDay: dayOffset,
   172→                            duration,
   173→                            type: taskTypes[typeIndex],
   174→                            color: colors[typeIndex],
   175→                            conflict: Math.random() < 0.05 // 5% have conflicts
   176→                        });
   177→                    }
   178→                }
   179→            });
   180→        }
   181→
   182→        // ========================================
   183→        // SIDEBAR
   184→        // ========================================
   185→        function renderSidebar() {
   186→            const visibleTrains = getVisibleTrains();
   187→            sidebar.innerHTML = visibleTrains.map(train => `
   188→                <div class="px-2 py-1 text-[10px] text-gray-700 border-b border-gray-100 truncate"
   189→                     style="height: ${CONFIG.PX_PER_TRAIN * state.zoom}px; line-height: ${CONFIG.PX_PER_TRAIN * state.zoom}px;">
   190→                    ${train.id}
   191→                </div>
   192→            `).join('');
   193→        }
   194→
   195→        function getVisibleTrains() {
   196→            const viewportHeight = canvas.height;
   197→            const startIndex = Math.max(0, Math.floor(-state.panY / (CONFIG.PX_PER_TRAIN * state.zoom)));
   198→            const endIndex = Math.min(CONFIG.TRAINS, startIndex + Math.ceil(viewportHeight / (CONFIG.PX_PER_TRAIN * state.zoom)) + 1);
   199→            return state.trains.slice(startIndex, endIndex);
   200→        }
   201→
   202→        // ========================================
   203→        // TIMELINE HEADER
   204→        // ========================================
   205→        function renderTimelineHeader() {
   206→            const viewportWidth = canvas.width;
   207→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   208→            const startDay = Math.floor(-state.panX / pxPerDay);
   209→            const endDay = startDay + Math.ceil(viewportWidth / pxPerDay) + 1;
   210→
   211→            let html = '';
   212→            const date = new Date(CONFIG.START_DATE);
   213→
   214→            // Determine granularity based on zoom
   215→            let step, format;
   216→            if (state.zoom < 0.3) {
   217→                step = 365; // Years
   218→                format = d => d.getFullYear();
   219→            } else if (state.zoom < 1) {
   220→                step = 30; // Months
   221→                format = d => d.toLocaleDateString('en', { month: 'short', year: '2-digit' });
   222→            } else if (state.zoom < 2) {
   223→                step = 7; // Weeks
   224→                format = d => d.toLocaleDateString('en', { month: 'short', day: 'numeric' });
   225→            } else {
   226→                step = 1; // Days
   227→                format = d => d.toLocaleDateString('en', { weekday: 'short', day: 'numeric' });
   228→            }
   229→
   230→            for (let day = Math.max(0, startDay - step); day < endDay; day += step) {
   231→                date.setTime(CONFIG.START_DATE.getTime() + day * 24 * 60 * 60 * 1000);
   232→                const x = day * pxPerDay + state.panX;
   233→                if (x >= -100 && x < viewportWidth + 100) {
   234→                    html += `<div class="absolute text-[10px] text-gray-500 whitespace-nowrap" style="left: ${x}px;">${format(date)}</div>`;
   235→                }
   236→            }
   237→
   238→            timelineHeader.innerHTML = html;
   239→        }
   240→
   241→        // ========================================
   242→        // LOD DETERMINATION
   243→        // ========================================
   244→        function getLOD() {
   245→            if (state.zoom < CONFIG.LOD_THRESHOLDS.MACRO) return 'MACRO';
   246→            if (state.zoom > CONFIG.LOD_THRESHOLDS.MICRO) return 'MICRO';
   247→            return 'MESO';
   248→        }
   249→
   250→        function updateLODIndicator() {
   251→            const lod = getLOD();
   252→            const colors = {
   253→                MACRO: 'bg-yellow-100 text-yellow-700',
   254→                MESO: 'bg-blue-100 text-blue-700',
   255→                MICRO: 'bg-green-100 text-green-700'
   256→            };
   257→            lodLevelEl.textContent = lod;
   258→            lodLevelEl.className = `font-mono font-semibold px-2 py-0.5 rounded ${colors[lod]}`;
   259→            state.currentLOD = lod;
   260→        }
   261→
   262→        // ========================================
   263→        // CANVAS RENDERING
   264→        // ========================================
   265→        function resizeCanvas() {
   266→            const container = canvas.parentElement;
   267→            canvas.width = container.clientWidth;
   268→            canvas.height = container.clientHeight - 32; // Account for timeline header
   269→            render();
   270→        }
   271→
   272→        function render() {
   273→            ctx.clearRect(0, 0, canvas.width, canvas.height);
   274→
   275→            const lod = getLOD();
   276→
   277→            switch (lod) {
   278→                case 'MACRO':
   279→                    renderMacroLayer();
   280→                    break;
   281→                case 'MESO':
   282→                    renderMesoLayer();
   283→                    break;
   284→                case 'MICRO':
   285→                    renderMicroLayer();
   286→                    break;
   287→            }
   288→
   289→            // Update micro overlay visibility
   290→            microOverlay.style.opacity = lod === 'MICRO' ? '1' : '0';
   291→            microOverlay.style.pointerEvents = lod === 'MICRO' ? 'auto' : 'none';
   292→
   293→            renderSidebar();
   294→            renderTimelineHeader();
   295→            zoomLevelEl.textContent = state.zoom.toFixed(2) + 'x';
   296→            updateLODIndicator();
   297→        }
   298→
   299→        // ========================================
   300→        // MACRO LAYER - Heatmap
   301→        // ========================================
   302→        function renderMacroLayer() {
   303→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   304→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   305→            const cellW = Math.max(4, pxPerDay * 30); // ~1 month per cell
   306→            const cellH = Math.max(4, pxPerTrain);
   307→
   308→            // Create task density map
   309→            const totalDays = CONFIG.YEARS * 365;
   310→            const cols = Math.ceil(totalDays / 30);
   311→            const rows = CONFIG.TRAINS;
   312→
   313→            for (let row = 0; row < rows; row++) {
   314→                for (let col = 0; col < cols; col++) {
   315→                    const x = col * cellW + state.panX;
   316→                    const y = row * cellH + state.panY;
   317→
   318→                    if (x > canvas.width || y > canvas.height || x + cellW < 0 || y + cellH < 0) continue;
   319→
   320→                    // Calculate density based on tasks in this cell
   321→                    const startDay = col * 30;
   322→                    const endDay = startDay + 30;
   323→                    const tasksInCell = state.tasks.filter(t =>
   324→                        t.trainIndex === row &&
   325→                        t.startDay < endDay &&
   326→                        t.startDay + t.duration > startDay
   327→                    ).length;
   328→
   329→                    const density = Math.min(1, tasksInCell / 10);
   330→                    ctx.fillStyle = getHeatColor(density);
   331→                    ctx.fillRect(x, y, cellW - 1, cellH - 1);
   332→                }
   333→            }
   334→        }
   335→
   336→        function getHeatColor(value) {
   337→            // Yellow -> Orange -> Red
   338→            if (value < 0.3) {
   339→                return `rgb(255, ${Math.floor(243 - value * 100)}, ${Math.floor(196 - value * 300)})`;
   340→            } else if (value < 0.6) {
   341→                const t = (value - 0.3) / 0.3;
   342→                return `rgb(255, ${Math.floor(180 - t * 80)}, ${Math.floor(100 - t * 80)})`;
   343→            } else {
   344→                const t = (value - 0.6) / 0.4;
   345→                return `rgb(${Math.floor(255 - t * 55)}, ${Math.floor(100 - t * 70)}, ${Math.floor(20 + t * 20)})`;
   346→            }
   347→        }
   348→
   349→        // ========================================
   350→        // MESO LAYER - DNA Strips
   351→        // ========================================
   352→        function renderMesoLayer() {
   353→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   354→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   355→
   356→            // Draw row backgrounds
   357→            for (let i = 0; i < CONFIG.TRAINS; i++) {
   358→                const y = i * pxPerTrain + state.panY;
   359→                if (y > canvas.height || y + pxPerTrain < 0) continue;
   360→
   361→                ctx.fillStyle = i % 2 === 0 ? '#fafafa' : '#f5f5f5';
   362→                ctx.fillRect(0, y, canvas.width, pxPerTrain);
   363→            }
   364→
   365→            // Draw tasks as blocks
   366→            const visibleTasks = state.tasks.filter(task => {
   367→                const x = task.startDay * pxPerDay + state.panX;
   368→                const y = task.trainIndex * pxPerTrain + state.panY;
   369→                const w = task.duration * pxPerDay;
   370→                return x + w > 0 && x < canvas.width && y + pxPerTrain > 0 && y < canvas.height;
   371→            });
   372→
   373→            visibleTasks.forEach(task => {
   374→                const x = task.startDay * pxPerDay + state.panX;
   375→                const y = task.trainIndex * pxPerTrain + state.panY + 2;
   376→                const w = Math.max(2, task.duration * pxPerDay - 2);
   377→                const h = pxPerTrain - 4;
   378→
   379→                const colors = {
   380→                    blue: ['#3b82f6', '#2563eb'],
   381→                    orange: ['#f59e0b', '#d97706'],
   382→                    gray: ['#9ca3af', '#6b7280']
   383→                };
   384→                const [c1, c2] = colors[task.color] || colors.blue;
   385→
   386→                const gradient = ctx.createLinearGradient(x, y, x + w, y + h);
   387→                gradient.addColorStop(0, c1);
   388→                gradient.addColorStop(1, c2);
   389→
   390→                ctx.fillStyle = gradient;
   391→                ctx.beginPath();
   392→                ctx.roundRect(x, y, w, h, 2);
   393→                ctx.fill();
   394→
   395→                // Conflict indicator
   396→                if (task.conflict) {
   397→                    ctx.strokeStyle = '#ef4444';
   398→                    ctx.lineWidth = 2;
   399→                    ctx.stroke();
   400→                }
   401→            });
   402→        }
   403→
   404→        // ========================================
   405→        // MICRO LAYER - Detailed Cards
   406→        // ========================================
   407→        function renderMicroLayer() {
   408→            const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
   409→            const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
   410→
   411→            // Draw grid
   412→            ctx.strokeStyle = '#e5e7eb';
   413→            ctx.lineWidth = 1;
   414→
   415→            // Vertical lines (days)
   416→            const startDay = Math.floor(-state.panX / pxPerDay);
   417→            const endDay = startDay + Math.ceil(canvas.width / pxPerDay) + 1;
   418→            for (let day = startDay; day < endDay; day++) {
   419→                const x = day * pxPerDay + state.panX;
   420→                ctx.beginPath();
   421→                ctx.moveTo(x, 0);
   422→                ctx.lineTo(x, canvas.height);
   423→                ctx.stroke();
   424→            }
   425→
   426→            // Horizontal lines (trains)
   427→            for (let i = 0; i <= CONFIG.TRAINS; i++) {
   428→                const y = i * pxPerTrain + state.panY;
   429→                if (y < 0 || y > canvas.height) continue;
   430→                ctx.beginPath();
   431→                ctx.moveTo(0, y);
   432→                ctx.lineTo(canvas.width, y);
   433→                ctx.stroke();
   434→            }
   435→
   436→            // Draw tasks with labels
   437→            const visibleTasks = state.tasks.filter(task => {
   438→                const x = task.startDay * pxPerDay + state.panX;
   439→                const y = task.trainIndex * pxPerTrain + state.panY;
   440→                const w = task.duration * pxPerDay;
   441→                return x + w > 0 && x < canvas.width && y + pxPerTrain > 0 && y < canvas.height;
   442→            });
   443→
   444→            visibleTasks.forEach(task => {
   445→                const x = task.startDay * pxPerDay + state.panX + 2;
   446→                const y = task.trainIndex * pxPerTrain + state.panY + 4;
   447→                const w = Math.max(20, task.duration * pxPerDay - 4);
   448→                const h = pxPerTrain - 8;
   449→
   450→                const colors = {
   451→                    blue: ['#3b82f6', '#2563eb'],
   452→                    orange: ['#f59e0b', '#d97706'],
   453→                    gray: ['#9ca3af', '#6b7280']
   454→                };
   455→                const [c1, c2] = colors[task.color] || colors.blue;
   456→
   457→                // Draw card shadow
   458→                ctx.fillStyle = 'rgba(0,0,0,0.1)';
   459→                ctx.beginPath();
   460→                ctx.roundRect(x + 2, y + 2, w, h, 4);
   461→                ctx.fill();
   462→
   463→                // Draw card
   464→                const gradient = ctx.createLinearGradient(x, y, x + w, y + h);
   465→                gradient.addColorStop(0, c1);
   466→                gradient.addColorStop(1, c2);
   467→                ctx.fillStyle = gradient;
   468→                ctx.beginPath();
   469→                ctx.roundRect(x, y, w, h, 4);
   470→                ctx.fill();
   471→
   472→                // Conflict border
   473→                if (task.conflict) {
   474→                    ctx.strokeStyle = '#ef4444';
   475→                    ctx.lineWidth = 2;
   476→                    ctx.shadowColor = '#ef4444';
   477→                    ctx.shadowBlur = 8;
   478→                    ctx.stroke();
   479→                    ctx.shadowBlur = 0;
   480→                }
   481→
   482→                // Draw text if space allows
   483→                if (w > 50) {
   484→                    ctx.fillStyle = '#ffffff';
   485→                    ctx.font = `${Math.min(12, h * 0.6)}px system-ui`;
   486→                    ctx.textBaseline = 'middle';
   487→                    const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);
   488→                    const textWidth = ctx.measureText(label).width;
   489→                    if (textWidth < w - 8) {
   490→                        ctx.fillText(label, x + 6, y + h / 2);
   491→                    }
   492→                }
   493→            });
   494→        }
   495→
   496→        // ========================================
   497→        // EVENT HANDLERS
   498→        // ========================================
   499→        function handleWheel(e) {
   500→            e.preventDefault();
   501→
   502→            const rect = canvas.getBoundingClientRect();
   503→            const mouseX = e.clientX - rect.left;
   504→            const mouseY = e.clientY - rect.top;
   505→
   506→            // Calculate zoom factor
   507→            const delta = -e.deltaY * CONFIG.ZOOM_SENSITIVITY;
   508→            const newZoom = Math.max(CONFIG.MIN_ZOOM, Math.min(CONFIG.MAX_ZOOM, state.zoom * (1 + delta)));
   509→
   510→            // Zoom toward mouse position
   511→            const zoomRatio = newZoom / state.zoom;
   512→            state.panX = mouseX - (mouseX - state.panX) * zoomRatio;
   513→            state.panY = mouseY - (mouseY - state.panY) * zoomRatio;
   514→            state.zoom = newZoom;
   515→
   516→            render();
   517→        }
   518→
   519→        function handleMouseDown(e) {
   520→            state.isDragging = true;
   521→            state.dragStartX = e.clientX;
   522→            state.dragStartY = e.clientY;
   523→            state.lastPanX = state.panX;
   524→            state.lastPanY = state.panY;
   525→            canvas.style.cursor = 'grabbing';
   526→        }
   527→
   528→        function handleMouseMove(e) {
   529→            if (!state.isDragging) return;
   530→
   531→            const dx = e.clientX - state.dragStartX;
   532→            const dy = e.clientY - state.dragStartY;
   533→            state.panX = state.lastPanX + dx;
   534→            state.panY = state.lastPanY + dy;
   535→
   536→            render();
   537→        }
   538→
   539→        function handleMouseUp() {
   540→            state.isDragging = false;
   541→            canvas.style.cursor = 'grab';
   542→        }
   543→
   544→        function handleDoubleClick(e) {
   545→            const rect = canvas.getBoundingClientRect();
   546→            const mouseX = e.clientX - rect.left;
   547→            const mouseY = e.clientY - rect.top;
   548→
   549→            // Zoom in 2x at click location
   550→            const newZoom = Math.min(CONFIG.MAX_ZOOM, state.zoom * 2);
   551→            const zoomRatio = newZoom / state.zoom;
   552→            state.panX = mouseX - (mouseX - state.panX) * zoomRatio;
   553→            state.panY = mouseY - (mouseY - state.panY) * zoomRatio;
   554→            state.zoom = newZoom;
   555→
   556→            render();
   557→        }
   558→
   559→        // Button handlers
   560→        document.getElementById('zoomIn').addEventListener('click', () => {
   561→            const centerX = canvas.width / 2;
   562→            const centerY = canvas.height / 2;
   563→            const newZoom = Math.min(CONFIG.MAX_ZOOM, state.zoom * 1.5);
   564→            const zoomRatio = newZoom / state.zoom;
   565→            state.panX = centerX - (centerX - state.panX) * zoomRatio;
   566→            state.panY = centerY - (centerY - state.panY) * zoomRatio;
   567→            state.zoom = newZoom;
   568→            render();
   569→        });
   570→
   571→        document.getElementById('zoomOut').addEventListener('click', () => {
   572→            const centerX = canvas.width / 2;
   573→            const centerY = canvas.height / 2;
   574→            const newZoom = Math.max(CONFIG.MIN_ZOOM, state.zoom / 1.5);
   575→            const zoomRatio = newZoom / state.zoom;
   576→            state.panX = centerX - (centerX - state.panX) * zoomRatio;
   577→            state.panY = centerY - (centerY - state.panY) * zoomRatio;
   578→            state.zoom = newZoom;
   579→            render();
   580→        });
   581→
   582→        document.getElementById('resetBtn').addEventListener('click', () => {
   583→            state.zoom = 1.0;
   584→            state.panX = 0;
   585→            state.panY = 0;
   586→            render();
   587→        });
   588→
   589→        // ========================================
   590→        // INITIALIZATION
   591→        // ========================================
   592→        function init() {
   593→            generateData();
   594→            resizeCanvas();
   595→
   596→            // Attach event listeners
   597→            canvas.addEventListener('wheel', handleWheel, { passive: false });
   598→            canvas.addEventListener('mousedown', handleMouseDown);
   599→            window.addEventListener('mousemove', handleMouseMove);
   600→            window.addEventListener('mouseup', handleMouseUp);
   601→            canvas.addEventListener('dblclick', handleDoubleClick);
   602→            window.addEventListener('resize', resizeCanvas);
   603→
   604→            // Hide instructions after 5 seconds
   605→            setTimeout(() => {
   606→                instructions.style.opacity = '0';
   607→            }, 5000);
   608→
   609→            render();
   610→        }
   611→
   612→        document.addEventListener('DOMContentLoaded', init);
   613→    </script>
   614→</body>
   615→</html>
