/**
 * What-If Scenario Types
 * Core feature for demonstrating the "mathematical model"
 */

import type { MasterPlan, ScheduleMetrics } from './schedule';

export type ScenarioType =
  | 'FLEET_CHANGE'
  | 'INTERVAL_CHANGE'
  | 'CAPACITY_CHANGE'
  | 'DEMAND_CHANGE'
  | 'CONSTRAINT_CHANGE'
  | 'MULTI_SCENARIO';

export interface ScenarioParameter {
  id: string;
  name: string;
  type: 'number' | 'percentage' | 'boolean' | 'select';
  currentValue: number | string | boolean;
  newValue: number | string | boolean;
  unit?: string;
  description?: string;
}

export interface Scenario {
  id: string;
  name: string;
  description?: string;
  type: ScenarioType;
  parameters: ScenarioParameter[];

  // Base reference
  basePlanId: string;

  // Status
  status: ScenarioStatus;

  // Results (populated after solving)
  resultPlan?: MasterPlan;
  comparison?: ScenarioComparison;

  // Metadata
  createdAt: string;
  updatedAt: string;
  createdBy?: string;
}

export type ScenarioStatus =
  | 'DRAFT'
  | 'PENDING'
  | 'SOLVING'
  | 'COMPLETED'
  | 'FAILED';

export interface ScenarioComparison {
  scenarioId: string;
  basePlanId: string;

  // Delta metrics
  workloadDelta: MetricDelta;
  costDelta: MetricDelta;
  complianceDelta: MetricDelta;
  utilizationDelta: MetricDelta;

  // Impact analysis
  resourceImpact: ResourceImpact;
  costImpact: CostImpact;
  complianceImpact: ComplianceImpact;
  feasibilityRisk: FeasibilityRisk;

  // Summary
  overallScore: number; // 0-100
  recommendation: string;
  highlights: string[];
  warnings: string[];
}

export interface MetricDelta {
  baseline: number;
  scenario: number;
  absoluteDelta: number;
  percentageDelta: number;
  trend: 'IMPROVED' | 'UNCHANGED' | 'DEGRADED';
}

export interface ResourceImpact {
  peakDemandChange: number;
  averageDemandChange: number;
  overCapacityPeriods: number;
  additionalResourcesNeeded: number;
}

export interface CostImpact {
  laborCostChange: number;
  partsCostChange: number;
  overheadCostChange: number;
  totalCostChange: number;
  percentageChange: number;
}

export interface ComplianceImpact {
  eventsOnTimeRate: number;
  eventsEarlyRate: number;
  eventsLateRate: number;
  riskScore: number; // 0-100
}

export interface FeasibilityRisk {
  level: 'LOW' | 'MEDIUM' | 'HIGH';
  factors: string[];
  mitigations: string[];
}

/**
 * Multi-scenario comparison for side-by-side analysis
 */
export interface MultiScenarioComparison {
  scenarios: Scenario[];
  baselineMetrics: ScheduleMetrics;
  rankings: ScenarioRanking[];
  recommendation: Scenario;
  summary: string;
}

export interface ScenarioRanking {
  scenarioId: string;
  criteria: string;
  rank: number;
  score: number;
}

/**
 * Preset scenario template interface for quick what-if analysis
 * Actual templates are defined in seed/configuration data
 */
export interface ScenarioTemplate {
  id: string;
  name: string;
  description: string;
  type: ScenarioType;
  parameters: Omit<ScenarioParameter, 'currentValue'>[];
  icon?: string;
}

