/**
 * API Types - Request/Response types for the backend
 */

import type { Asset, Fleet, MileageForecast, RUCStatus } from './asset';
import type { MaintenanceEvent, MaintenanceConfig } from './maintenance';
import type { MasterPlan, ScheduleMetrics } from './schedule';
import type { Scenario, ScenarioComparison, MultiScenarioComparison } from './scenario';
import type { SolverInput, SolverOutput, SolverJob } from './solver';

/**
 * Generic API response wrapper
 */
export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: ApiError;
  meta?: ApiMeta;
}

export interface ApiError {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

export interface ApiMeta {
  requestId: string;
  timestamp: string;
  duration: number;
}

/**
 * Pagination
 */
export interface PaginatedRequest {
  page?: number;
  pageSize?: number;
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
}

export interface PaginatedResponse<T> {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/**
 * Assets API
 */
export interface GetAssetsRequest extends PaginatedRequest {
  trainType?: string;
  status?: string;
}

export interface GetAssetsResponse extends PaginatedResponse<Asset> {}

export interface GetFleetRequest {
  includeAssets?: boolean;
}

export interface GetFleetResponse {
  fleet: Fleet;
  rucStatuses?: RUCStatus[];
}

/**
 * Maintenance API
 */
export interface GetEventsRequest extends PaginatedRequest {
  assetId?: string;
  status?: string;
  level?: string;
  fromWeek?: number;
  toWeek?: number;
}

export interface GetEventsResponse extends PaginatedResponse<MaintenanceEvent> {}

export interface GetConfigResponse {
  config: MaintenanceConfig;
}

/**
 * Schedule API
 */
export interface GetMasterPlanRequest {
  planId: string;
  includeEvents?: boolean;
  includeMetrics?: boolean;
}

export interface GetMasterPlanResponse {
  plan: MasterPlan;
}

export interface GeneratePlanRequest {
  name: string;
  description?: string;
  startWeek: number;
  startYear: number;
  horizonWeeks: number;
  config?: Partial<MaintenanceConfig>;
}

export interface GeneratePlanResponse {
  jobId: string;
}

export interface GetWorkloadProfileRequest {
  planId: string;
  fromWeek?: number;
  toWeek?: number;
  aggregation?: 'WEEKLY' | 'MONTHLY' | 'QUARTERLY';
}

export interface GetWorkloadProfileResponse {
  profile: {
    period: string;
    manHours: number;
    capacity: number;
    utilization: number;
  }[];
  metrics: ScheduleMetrics;
}

/**
 * Scenario (What-If) API
 */
export interface CreateScenarioRequest {
  name: string;
  description?: string;
  basePlanId: string;
  type: Scenario['type'];
  parameters: Scenario['parameters'];
}

export interface CreateScenarioResponse {
  scenario: Scenario;
}

export interface RunScenarioRequest {
  scenarioId: string;
}

export interface RunScenarioResponse {
  jobId: string;
}

export interface GetScenarioResultRequest {
  scenarioId: string;
}

export interface GetScenarioResultResponse {
  scenario: Scenario;
  comparison: ScenarioComparison;
}

export interface CompareMultipleScenariosRequest {
  scenarioIds: string[];
}

export interface CompareMultipleScenariosResponse {
  comparison: MultiScenarioComparison;
}

/**
 * Solver API
 */
export interface SolveRequest {
  input: SolverInput;
}

export interface SolveResponse {
  jobId: string;
}

export interface GetSolverJobRequest {
  jobId: string;
}

export interface GetSolverJobResponse {
  job: SolverJob;
}

/**
 * WebSocket events for real-time updates
 */
export type WebSocketEvent =
  | { type: 'SOLVER_PROGRESS'; jobId: string; progress: number }
  | { type: 'SOLVER_COMPLETE'; jobId: string; output: SolverOutput }
  | { type: 'SOLVER_ERROR'; jobId: string; error: string }
  | { type: 'PLAN_UPDATED'; planId: string }
  | { type: 'SCENARIO_COMPLETE'; scenarioId: string };

