const instructions = document.getElementById('instructions');

// ========================================
// DATA GENERATION
// ========================================
function generateData() {
    // Generate trains
    state.trains = Array.from({ length: CONFIG.TRAINS }, (_, i) => ({
        id: `T${String(i + 1).padStart(3, '0')}`,
        name: `Train ${i + 1}`,
        type: i < 30 ? 'ALSTOM' : 'KINKI'
    }));

    // Generate tasks
    state.tasks = [];
    const taskTypes = ['maintenance', 'overhaul', 'inspection'];
    const colors = ['blue', 'orange', 'gray'];

    state.trains.forEach((train, trainIndex) => {
        // Generate ~10 tasks per year per train
        for (let year = 0; year < CONFIG.YEARS; year++) {
            const tasksPerYear = 8 + Math.floor(Math.random() * 5);
            for (let t = 0; t < tasksPerYear; t++) {
                const dayOffset = year * 365 + Math.floor(Math.random() * 360);
                const duration = 2 + Math.floor(Math.random() * 10);
                const typeIndex = Math.floor(Math.random() * taskTypes.length);

                state.tasks.push({
                    id: `${train.id}-${year}-${t}`,
                    trainId: train.id,
                    trainIndex,
                    startDay: dayOffset,
                    duration,
                    type: taskTypes[typeIndex],
                    color: colors[typeIndex],
                    conflict: Math.random() < 0.05 // 5% have conflicts
                });
            }
        }
    });
}

// ========================================
// SIDEBAR
// ========================================
function renderSidebar() {
    const visibleTrains = getVisibleTrains();
    sidebar.innerHTML = visibleTrains.map(train => `
        <div class="px-2 py-1 text-[10px] text-gray-700 border-b border-gray-100 truncate"
             style="height: ${CONFIG.PX_PER_TRAIN * state.zoom}px; line-height: ${CONFIG.PX_PER_TRAIN * state.zoom}px;">
            ${train.id}
        </div>
    `).join('');
}

function getVisibleTrains() {
    const viewportHeight = canvas.height;
    const startIndex = Math.max(0, Math.floor(-state.panY / (CONFIG.PX_PER_TRAIN * state.zoom)));
    const endIndex = Math.min(CONFIG.TRAINS, startIndex + Math.ceil(viewportHeight / (CONFIG.PX_PER_TRAIN * state.zoom)) + 1);
    return state.trains.slice(startIndex, endIndex);
}

// ========================================
// TIMELINE HEADER
// ========================================
function renderTimelineHeader() {
    const viewportWidth = canvas.width;
    const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
    const startDay = Math.floor(-state.panX / pxPerDay);
    const endDay = startDay + Math.ceil(viewportWidth / pxPerDay) + 1;

    let html = '';
    const date = new Date(CONFIG.START_DATE);

    // Determine granularity based on zoom
    let step, format;
    if (state.zoom < 0.3) {
        step = 365; // Years
        format = d => d.getFullYear();
    } else if (state.zoom < 1) {
        step = 30; // Months
        format = d => d.toLocaleDateString('en', { month: 'short', year: '2-digit' });
    } else if (state.zoom < 2) {
        step = 7; // Weeks
        format = d => d.toLocaleDateString('en', { month: 'short', day: 'numeric' });
    } else {
        step = 1; // Days
        format = d => d.toLocaleDateString('en', { weekday: 'short', day: 'numeric' });
    }

    for (let day = Math.max(0, startDay - step); day < endDay; day += step) {
        date.setTime(CONFIG.START_DATE.getTime() + day * 24 * 60 * 60 * 1000);
        const x = day * pxPerDay + state.panX;
        if (x >= -100 && x < viewportWidth + 100) {
            html += `<div class="absolute text-[10px] text-gray-500 whitespace-nowrap" style="left: ${x}px;">${format(date)}</div>`;
        }
    }

    timelineHeader.innerHTML = html;
}

// ========================================
// LOD DETERMINATION
// ========================================
function getLOD() {
    if (state.zoom < CONFIG.LOD_THRESHOLDS.MACRO) return 'MACRO';
    if (state.zoom > CONFIG.LOD_THRESHOLDS.MICRO) return 'MICRO';
    return 'MESO';
}

function updateLODIndicator() {
    const lod = getLOD();
    const colors = {
        MACRO: 'bg-yellow-100 text-yellow-700',
        MESO: 'bg-blue-100 text-blue-700',
        MICRO: 'bg-green-100 text-green-700'
    };
    lodLevelEl.textContent = lod;
    lodLevelEl.className = `font-mono font-semibold px-2 py-0.5 rounded ${colors[lod]}`;
    state.currentLOD = lod;
}

// ========================================
// CANVAS RENDERING
// ========================================
function resizeCanvas() {
    const container = canvas.parentElement;
    canvas.width = container.clientWidth;
    canvas.height = container.clientHeight - 32; // Account for timeline header
    render();
}

function render() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const lod = getLOD();

    switch (lod) {
        case 'MACRO':
            renderMacroLayer();
            break;
        case 'MESO':
            renderMesoLayer();
            break;
        case 'MICRO':
            renderMicroLayer();
            break;
    }

    // Update micro overlay visibility
    microOverlay.style.opacity = lod === 'MICRO' ? '1' : '0';
    microOverlay.style.pointerEvents = lod === 'MICRO' ? 'auto' : 'none';

    renderSidebar();
    renderTimelineHeader();
    zoomLevelEl.textContent = state.zoom.toFixed(2) + 'x';
    updateLODIndicator();
}

// ========================================
// MACRO LAYER - Heatmap
// ========================================
function renderMacroLayer() {
    const pxPerDay = CONFIG.PX_PER_DAY * state.zoom;
    const pxPerTrain = CONFIG.PX_PER_TRAIN * state.zoom;
    const cellW = Math.max(4, pxPerDay * 30); // ~1 month per cell
    const cellH = Math.max(4, pxPerTrain);

    // Create task density map
    const totalDays = CONFIG.YEARS * 365;
    const cols = Math.ceil(totalDays / 30);
    const rows = CONFIG.TRAINS;

    for (let row = 0; row < rows; row++) {
        for (let col = 0; col < cols; col++) {
            const x = col * cellW + state.panX;
            const y = row * cellH + state.panY;

            if (x > canvas.width || y > canvas.height || x + cellW < 0 || y + cellH < 0) continue;

            // Calculate density based on tasks in this cell
            const startDay = col * 30;
            const endDay = startDay + 30;
            const tasksInCell = state.tasks.filter(t =>
                t.trainIndex === row &&
                t.startDay < endDay &&
                t.startDay + t.duration > startDay
            ).length;

            const density = Math.min(1, tasksInCell / 10);
            ctx.fillStyle = getHeatColor(density);
            ctx.fillRect(x, y, cellW - 1, cellH - 1);
        }
    }
}

function getHeatColor(value) {
    // Yellow -> Orange -> Red
    if (value < 0.3) {
        return `rgb(255, ${Math.floor(243 - value * 100)}, ${Math.floor(196 - value * 300)})`;

