/**
 * Mock Data Generator
 *
 * Generates test data for the MMS visualization:
 * - 50 trains (30 ALSTOM + 20 KINKI)
 * - 10 years of tasks per train
 * - ~10-12 tasks per train per year
 * - ~5% of tasks have conflict flags
 */

import {
  Train,
  Task,
  TaskRender,
  GeneratedData,
  DatasetMeta,
  TaskType,
  AssetType,
  TYPE_TO_COLOR,
  DEFAULT_DATASET_META,
} from './types';

// ─────────────────────────────────────────────────────────────
// DATE HELPERS
// ─────────────────────────────────────────────────────────────

/**
 * Format date as ISO 8601 string (YYYY-MM-DD)
 */
function formatISO(date: Date): string {
  return date.toISOString().split('T')[0];
}

/**
 * Add days to a date
 */
function addDays(date: Date | string, days: number): Date {
  const d = typeof date === 'string' ? new Date(date) : new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

/**
 * Calculate days between two dates
 */
function daysBetween(start: Date | string, end: Date | string): number {
  const s = typeof start === 'string' ? new Date(start) : start;
  const e = typeof end === 'string' ? new Date(end) : end;
  const diffTime = e.getTime() - s.getTime();
  return Math.floor(diffTime / (1000 * 60 * 60 * 24));
}

// ─────────────────────────────────────────────────────────────
// DATA GENERATION
// ─────────────────────────────────────────────────────────────

/**
 * Generate train entities
 */
function generateTrains(count: number): Train[] {
  return Array.from({ length: count }, (_, i) => {
    const isAlstom = i < Math.floor(count * 0.6); // 60% Alstom
    return {
      id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
      name: `Train ${i + 1}`,
      assetType: (isAlstom ? 'ALSTOM' : 'KINKI') as AssetType,
    };
  });
}

/**
 * Generate tasks for all trains
 */
function generateTasks(trains: Train[], meta: DatasetMeta): Task[] {
  const tasks: Task[] = [];
  const types: TaskType[] = ['maintenance', 'overhaul', 'inspection'];

  trains.forEach((train) => {
    for (let year = 0; year < meta.years; year++) {
      // 8-12 tasks per year per train
      const tasksPerYear = 8 + Math.floor(Math.random() * 5);

      for (let t = 0; t < tasksPerYear; t++) {
        const dayOffset = year * 365 + Math.floor(Math.random() * 360);
        const duration = 2 + Math.floor(Math.random() * 10);
        const startDate = addDays(meta.startDate, dayOffset);
        const endDate = addDays(startDate, duration);

        tasks.push({
          id: `${train.id}-${year}-${t}`,
          trainId: train.id,
          startDate: formatISO(startDate),
          endDate: formatISO(endDate),
          type: types[Math.floor(Math.random() * types.length)],
          hasConflict: Math.random() < 0.05, // 5% conflict rate
        });
      }
    }
  });

  return tasks;
}

/**
 * Generate complete dataset
 */
export function generateData(meta: DatasetMeta = DEFAULT_DATASET_META): GeneratedData {
  const trains = generateTrains(meta.trainCount);
  const tasks = generateTasks(trains, meta);

  return { trains, tasks, meta };
}

// ─────────────────────────────────────────────────────────────
// RENDER DATA PREPARATION
// ─────────────────────────────────────────────────────────────

/**
 * Transform persistent data to render-ready format
 *
 * Converts:
 * - trainId → trainIndex (Y position)
 * - startDate/endDate → startDay/duration (X position and width)
 * - type → color
 */
export function prepareRenderData(data: GeneratedData): {
  trains: Train[];
  tasks: TaskRender[];
} {
  // Create train index lookup map
  const trainIndexMap = new Map<string, number>(
    data.trains.map((t, i) => [t.id, i])
  );

  // Transform tasks to render format
  const tasks: TaskRender[] = data.tasks.map((task) => {
    const trainIndex = trainIndexMap.get(task.trainId);
    if (trainIndex === undefined) {
      throw new Error(`Train not found: ${task.trainId}`);
    }

    const startDay = daysBetween(data.meta.startDate, task.startDate);
    const duration = daysBetween(task.startDate, task.endDate);

    return {
      id: task.id,
      trainIndex,
      startDay,
      duration,
      color: TYPE_TO_COLOR[task.type],
      hasConflict: task.hasConflict,
      type: task.type,
    };
  });

  return { trains: data.trains, tasks };
}

// ─────────────────────────────────────────────────────────────
// PRE-GENERATED DATA (for immediate use)
// ─────────────────────────────────────────────────────────────

// Generate data once at module load for consistent results
const _generatedData = generateData();
const _renderData = prepareRenderData(_generatedData);

/**
 * Get pre-generated dataset (persistent format)
 */
export function getData(): GeneratedData {
  return _generatedData;
}

/**
 * Get pre-generated render data (canvas-ready format)
 */
export function getRenderData(): { trains: Train[]; tasks: TaskRender[] } {
  return _renderData;
}

/**
 * Get just the trains array
 */
export function getTrains(): Train[] {
  return _generatedData.trains;
}

/**
 * Get just the render tasks array
 */
export function getTasks(): TaskRender[] {
  return _renderData.tasks;
}

